<?php namespace App\Services; use Illuminate\Http\Client\Factory as HttpFactory; use Illuminate\Support\Facades\Cache; use RuntimeException; class GoogleDocumentAiOcr { public function __construct(private readonly HttpFactory $http) { } protected function getAccessToken(): string { $credentials = config('services.document_ai.credentials_json'); if (!$credentials) { throw new RuntimeException('Google Document AI credentials are not configured.'); } $config = json_decode($credentials, true); if (!is_array($config) || !isset($config['client_email']) || !isset($config['private_key'])) { throw new RuntimeException('Invalid Google Document AI credentials JSON format.'); } $cacheKey = 'google_document_ai_access_token_' . md5($config['client_email']); if ($token = Cache::get($cacheKey)) { return $token; } $header = $this->base64UrlEncode(json_encode(['alg' => 'RS256', 'typ' => 'JWT'])); $payload = $this->base64UrlEncode(json_encode([ 'iss' => $config['client_email'], 'scope' => 'https://www.googleapis.com/auth/cloud-platform', 'aud' => 'https://oauth2.googleapis.com/token', 'exp' => time() + 3600, 'iat' => time(), ])); $signature = ''; $privateKey = $config['private_key']; if (!@openssl_sign("$header.$payload", $signature, $privateKey, OPENSSL_ALGO_SHA256)) { throw new RuntimeException('Failed to sign JWT for Google OAuth. Please check the private key format.'); } $jwt = "$header.$payload." . $this->base64UrlEncode($signature); $response = $this->http->asForm()->post('https://oauth2.googleapis.com/token', [ 'grant_type' => 'urn:ietf:params:oauth:grant-type:jwt-bearer', 'assertion' => $jwt, ]); if ($response->failed()) { throw new RuntimeException('Failed to obtain Google access token: ' . $response->body()); } $accessToken = $response->json('access_token'); $expiresIn = $response->json('expires_in', 3600); Cache::put($cacheKey, $accessToken, now()->addSeconds($expiresIn - 300)); return $accessToken; } private function base64UrlEncode(string $data): string { return str_replace(['+', '/', '='], ['-', '_', ''], base64_encode($data)); } public function process(string $filePath, ?string $mimeType = null): array { $projectId = config('services.document_ai.project_id'); $location = config('services.document_ai.location', 'us'); $processorId = config('services.document_ai.processor_id'); if (!$projectId || !$processorId) { throw new RuntimeException('Google Document AI project ID or processor ID is not configured.'); } if (!is_file($filePath) || !is_readable($filePath)) { throw new RuntimeException('Document file is not readable.'); } $mimeType = $mimeType ?: mime_content_type($filePath) ?: 'image/jpeg'; $content = base64_encode((string) file_get_contents($filePath)); $token = $this->getAccessToken(); $endpoint = "https://{$location}-documentai.googleapis.com/v1/projects/{$projectId}/locations/{$location}/processors/{$processorId}:process"; $response = $this->http->withHeaders([ 'Authorization' => 'Bearer ' . $token, 'Content-Type' => 'application/json', ])->timeout((int) config('services.document_ai.timeout', 30))->post($endpoint, [ 'rawDocument' => [ 'content' => $content, 'mimeType' => $mimeType, ], ]); if ($response->failed()) { throw new RuntimeException('Google Document AI API returned status ' . $response->status() . ': ' . $response->body()); } $text = $response->json('document.text'); return [ 'raw_text' => $text, 'document' => $response->json('document'), ]; } }
